INSERT INTO "public"."content_items" ("id", "language_code", "content_type", "slug", "title", "payload", "sort_order", "is_active", "created_at", "updated_at", "editorial_status", "is_startable", "content_version", "published_at") VALUES ('24de46ff-e1f5-47fd-92ff-b4015e1679e1', 'lg', 'card_game', 'cards', 'Buganda Cultural Cards', '{"items":[{"id":"card-lg-001","info":"The King of Buganda, one of the most powerful traditional monarchs in Uganda.","order":1,"value":"Kabaka","imageSymbol":"👑"},{"id":"card-lg-002","info":"The royal palace of the Kabaka of Buganda located in Mengo, Kampala.","order":2,"value":"Lubiri","imageSymbol":"🏰"},{"id":"card-lg-003","info":"Steamed green bananas, a staple food in Buganda cuisine.","order":3,"value":"Matoke","imageSymbol":"🍌"},{"id":"card-lg-004","info":"Traditional white robe worn by Baganda men, especially during ceremonies.","order":4,"value":"Kanzu","imageSymbol":"👘"},{"id":"card-lg-005","info":"A colorful floor-length dress worn by Baganda women during ceremonies.","order":5,"value":"Gomesi","imageSymbol":"👗"},{"id":"card-lg-006","info":"Traditional drums used in Kiganda music and royal ceremonies.","order":6,"value":"Engoma","imageSymbol":"🥁"},{"id":"card-lg-007","info":"The parliament or council of the Buganda Kingdom.","order":7,"value":"Lukiiko","imageSymbol":"🏛️"},{"id":"card-lg-008","info":"Traditional fables and stories that teach moral lessons in Buganda culture.","order":8,"value":"Olugero","imageSymbol":"📚"},{"id":"card-lg-009","info":"A traditional Baganda dance performed at cultural celebrations.","order":9,"value":"Bakisimba","imageSymbol":"💃"},{"id":"card-lg-010","info":"A traditional board game played throughout Uganda, especially in Buganda.","order":10,"value":"Mweso","imageSymbol":"🎮"},{"id":"card-lg-011","info":"A traditional flute used in Kiganda music.","order":11,"value":"Endere","imageSymbol":"🎵"},{"id":"card-lg-012","info":"A xylophone-like instrument with wooden keys used in traditional music.","order":12,"value":"Amadinda","imageSymbol":"🎹"},{"id":"card-lg-013","info":"The traditional territories or counties of Buganda Kingdom.","order":13,"value":"Ensi","imageSymbol":"🗺️"},{"id":"card-lg-014","info":"The title given to the mother of the Kabaka (King) of Buganda.","order":14,"value":"Namasole","imageSymbol":"👸"},{"id":"card-lg-015","info":"The prime minister or chief minister of the Buganda Kingdom.","order":15,"value":"Katikkiro","imageSymbol":"👔"},{"id":"card-lg-016","info":"An honorific title for the Kabaka, meaning ''Chief of Men''.","order":16,"value":"Ssabasajja","imageSymbol":"🤴"},{"id":"card-lg-017","info":"The royal burial grounds where Buganda kings are laid to rest.","order":17,"value":"Kasubi","imageSymbol":"⚱️"},{"id":"card-lg-018","info":"Traditional community service practice in Buganda culture.","order":18,"value":"Bulungi Bwansi","imageSymbol":"🌱"},{"id":"card-lg-019","info":"The traditional pillars that support the Buganda social structure.","order":19,"value":"Empagi","imageSymbol":"🏗️"},{"id":"card-lg-020","info":"Traditional walking stick symbolizing authority in Buganda culture.","order":20,"value":"Akendo","imageSymbol":"🦯"},{"id":"card-lg-021","info":"Clan totems that are sacred and respected in Buganda tradition.","order":21,"value":"Omuziro","imageSymbol":"🐘"},{"id":"card-lg-022","info":"The royal scepter, a symbol of the Kabaka''s authority.","order":22,"value":"Ddamula","imageSymbol":"🔱"},{"id":"card-lg-023","info":"A traditional Buganda dish of meat stewed in banana leaves.","order":23,"value":"Luwombo","imageSymbol":"🍲"},{"id":"card-lg-024","info":"A historic location in Buganda that means ''seat'' or ''chair'' in Luganda.","order":24,"value":"Entebbe","imageSymbol":"🪑"},{"id":"card-lg-025","info":"Traditional festivities or celebrations in Buganda culture.","order":25,"value":"Embaga","imageSymbol":"🎉"},{"id":"card-lg-026","info":"Special beads worn by members of the royal family.","order":26,"value":"Enkula","imageSymbol":"📿"},{"id":"card-lg-027","info":"Grasshoppers, a traditional delicacy in Buganda cuisine.","order":27,"value":"Enseenene","imageSymbol":"🦗"},{"id":"card-lg-028","info":"A person belonging to the Baganda ethnic group.","order":28,"value":"Muganda","imageSymbol":"👨"},{"id":"card-lg-029","info":"Royal title for the Kabaka meaning ''Chief of Chiefs''.","order":29,"value":"Ssaabasajja","imageSymbol":"👑"},{"id":"card-lg-030","info":"The royal throne of the Buganda Kingdom.","order":30,"value":"Namulondo","imageSymbol":"👑"},{"id":"card-lg-031","info":"A royal title in some kingdoms neighboring Buganda.","order":31,"value":"Kyabazinga","imageSymbol":"👑"},{"id":"card-lg-032","info":"The Luganda language, spoken by the Baganda people.","order":32,"value":"Oluganda","imageSymbol":"🗣️"},{"id":"card-lg-033","info":"Traditional fabric made from the Mutuba tree, used for ceremonies.","order":33,"value":"Barkcloth","imageSymbol":"🧵"},{"id":"card-lg-034","info":"Traditional visiting practices in Buganda culture.","order":34,"value":"Okukyala","imageSymbol":"🚶"},{"id":"card-lg-035","info":"A small drum in the ensemble of Kiganda music.","order":35,"value":"Nankere","imageSymbol":"🪘"},{"id":"card-lg-036","info":"Royal tombs or burial places for Buganda royalty.","order":36,"value":"Masiro","imageSymbol":"🏛️"},{"id":"card-lg-037","info":"The traditional fireplace where families gather for stories.","order":37,"value":"Ekyoto","imageSymbol":"🔥"},{"id":"card-lg-038","info":"Traditional ceremonial spears used in Buganda rituals.","order":38,"value":"Entamu","imageSymbol":"🗡️"},{"id":"card-lg-039","info":"Baby naming ceremony in Buganda culture.","order":39,"value":"Okuggya Omwana","imageSymbol":"👶"},{"id":"card-lg-040","info":"Traditional introduction ceremony before marriage in Buganda.","order":40,"value":"Okwanjula","imageSymbol":"💍"},{"id":"card-lg-041","info":"A legendary figure in Buganda history and culture.","order":41,"value":"Kaggwa","imageSymbol":"🦸"},{"id":"card-lg-042","info":"Ancestral spirits venerated in traditional Buganda beliefs.","order":42,"value":"Musambwa","imageSymbol":"👻"},{"id":"card-lg-043","info":"A mythical creature in Buganda folklore.","order":43,"value":"Kawulugumo","imageSymbol":"🐲"},{"id":"card-lg-044","info":"Honor and respect, a core value in Buganda culture.","order":44,"value":"Ekitiibwa","imageSymbol":"🙏"},{"id":"card-lg-045","info":"Traditional gift-giving practice in Buganda.","order":45,"value":"Akasiimo","imageSymbol":"🎁"},{"id":"card-lg-046","info":"Royal clan lineages in Buganda Kingdom.","order":46,"value":"Obusinga","imageSymbol":"👪"},{"id":"card-lg-047","info":"Traditional cowrie shells once used as currency.","order":47,"value":"Ensimbi","imageSymbol":"🐚"}],"title":"Buganda Cultural Cards"}', 55, true, '2026-07-14 21:34:23.334371+00', '2026-07-14 21:34:32.860724+00', 'published', true, 1, '2026-07-14 18:23:26+00'), ('27d66d37-f68b-4760-8ec9-0fe7ab919573', 'lg', 'story', 'fig-tree', 'The Generous Fig Tree', '{"id":"fig-tree","pages":[{"id":"fig-tree-page-1","text":"In a small village in Buganda, there grew a magnificent Mutuba fig tree. Its branches stretched wide, providing shade for everyone in the village.","image":"coin.png","altText":"A large fig tree providing shade to villagers"},{"id":"fig-tree-page-2","text":"The tree was not just any tree—it produced the bark cloth that was precious to the Baganda people. This cloth was used for ceremonial robes, bedding, and even burial shrouds.","image":"coin.png","altText":"People making bark cloth from the fig tree"},{"id":"fig-tree-page-3","text":"A poor woman named Nakawala lived near the tree. Each day, the tree would drop a single fig at her doorstep, which she would eat to survive.","image":"coin.png","altText":"A woman picking up a fig from her doorstep"},{"id":"fig-tree-page-4","text":"The village chief noticed how healthy Nakawala looked despite her poverty. He became curious and decided to watch her house to discover her secret.","image":"coin.png","altText":"The chief watching the woman''s house from a distance"},{"id":"fig-tree-page-5","text":"When he saw the fig tree drop its fruit for Nakawala, he became greedy. ''If one fig makes her so healthy, what would happen if I ate all the figs?'' he thought.","image":"coin.png","altText":"The chief looking greedily at the fig tree"},{"id":"fig-tree-page-6","text":"The chief ordered his men to collect every fig from the tree, leaving none for Nakawala or the birds and animals that depended on it. They took baskets full of figs to his home.","image":"coin.png","altText":"Men collecting all the figs from the tree in baskets"},{"id":"fig-tree-page-7","text":"That night, a terrible storm came. Lightning struck the chief''s house, destroying only the room where the figs were stored. The next morning, the fig tree had disappeared completely.","image":"coin.png","altText":"Lightning striking the chief''s house during a storm"},{"id":"fig-tree-page-8","text":"But a new sapling appeared at Nakawala''s doorstep. The tree had chosen to move where it was appreciated. The Baganda learned that generosity should be met with gratitude, not greed.","image":"coin.png","altText":"A small fig tree sapling growing at the woman''s doorstep"}],"title":"The Generous Fig Tree","summary":"Discover the story of the generous fig tree","metadata":{"notes":"Migrated from legacy hardcoded Luganda story components into content_items-compatible story payloads.","status":"existing-prototype"},"questions":[{"id":"fig-tree-question-1","options":["It could talk","It produced bark cloth precious to the Baganda","It had golden leaves","It never lost its leaves in dry season"],"question":"What was special about the Mutuba fig tree?","correctAnswer":1},{"id":"fig-tree-question-2","options":["By telling her stories","By dropping a single fig at her doorstep each day","By providing shade for her house","By healing her illnesses"],"question":"How did the fig tree help Nakawala?","correctAnswer":1},{"id":"fig-tree-question-3","options":["He wanted to marry her","He noticed how healthy she looked despite her poverty","He wanted her land","He thought she was stealing from others"],"question":"Why did the village chief become interested in Nakawala?","correctAnswer":1},{"id":"fig-tree-question-4","options":["He thanked the tree","He ordered his men to collect every fig from the tree","He shared the figs with everyone","He planted more fig trees"],"question":"What did the chief do when he discovered the fig tree''s gift?","correctAnswer":1},{"id":"fig-tree-question-5","options":["Trees are more valuable than gold","Generosity should be met with gratitude, not greed","Chiefs always know best","Poor people are often the wisest"],"question":"What lesson does this story teach?","correctAnswer":1}],"languageCode":"lg"}', 67, true, '2026-07-01 09:45:23.564353+00', '2026-07-14 21:34:32.860724+00', 'published', true, 1, '2026-07-14 18:23:26+00'), ('2a9fe57b-7e37-4998-b112-52761d0e0304', 'nyn', 'learning_game', 'starter', 'Runyankole Starter Learning', '{"stages":[{"id":1,"color":"#0F766E","image":"learning-beginner.jpg","title":"Runyankole Starter Samples","levels":[{"id":1,"title":"Greetings","words":[{"id":"nyn-word-agandi","audio":"correct.mp3","image":"learning-beginner.jpg","english":"How are you? / Other news?","example":"Agandi?","targetText":"Agandi","exampleTranslation":"How are you?"},{"id":"nyn-word-nimarungi","audio":"correct.mp3","image":"learning-beginner.jpg","english":"Good news / I am fine","example":"Nimarungi.","targetText":"Nimarungi","exampleTranslation":"I am fine."},{"id":"nyn-word-webare","audio":"correct.mp3","image":"learning-beginner.jpg","english":"Thank you","example":"Webare munonga.","targetText":"Webare","exampleTranslation":"Thank you very much."}],"isLocked":false}],"isLocked":false,"description":"Placeholder greetings and home words for testing language-specific lessons.","requiredScore":0}]}', 30, true, '2026-06-19 07:58:49.994863+00', '2026-07-14 21:34:32.860724+00', 'draft', false, 1, null), ('2c145cc1-0be7-4dc4-9bfe-0da9db22b701', 'lg', 'story', 'kasubi-tombs', 'Kasubi Tombs Story', '{"id":"kasubi-tombs","pages":[{"id":"kasubi-tombs-page-1","text":"The story of Kasubi Tombs begins with Kabaka Mutesa I, who ruled Buganda from 1856 to 1884. He was a powerful king who established contact with Arab traders and European explorers.","image":"coin.png","altText":"Kabaka Mutesa I sitting in royal attire meeting with visitors"},{"id":"kasubi-tombs-page-2","text":"In 1882, Mutesa I built his palace at Kasubi Hill. It was a magnificent traditional building called Muzibu-Azaala-Mpanga, with a large circular thatched roof and walls made of reeds.","image":"coin.png","altText":"Construction of the grand palace with traditional materials"},{"id":"kasubi-tombs-page-3","text":"When Kabaka Mutesa I died in 1884, the Baganda people decided to bury him inside his own palace. This was unusual, as kings were typically buried at different sites around the kingdom.","image":"coin.png","altText":"A funeral procession bringing Mutesa I to his final resting place"},{"id":"kasubi-tombs-page-4","text":"The palace was converted into a royal tomb, and a sacred place where people could connect with the spirit of their beloved king. Special caretakers called Naalinya, royal princesses, were appointed to tend to the site.","image":"coin.png","altText":"Naalinya princesses tending to the royal tomb"},{"id":"kasubi-tombs-page-5","text":"After Mutesa I, three more Buganda kings (Mwanga II, Daudi Chwa II, and Edward Mutesa II) were also buried at Kasubi. Each king has a sacred shrine within the main building.","image":"coin.png","altText":"The four royal burial areas within the main building"},{"id":"kasubi-tombs-page-6","text":"The tombs became a center of Buganda spiritual life. The main tomb house represents the entire kingdom, with the central poles symbolizing the clans of Buganda and the king as their unifier.","image":"coin.png","altText":"People gathering at the tombs for spiritual ceremonies"},{"id":"kasubi-tombs-page-7","text":"Inside the tombs are royal treasures, including the kings'' jawbones, which the Baganda believe contain the spirits of the deceased kings. These are kept behind a sacred bark cloth curtain.","image":"coin.png","altText":"Sacred bark cloth curtains protecting royal artifacts"},{"id":"kasubi-tombs-page-8","text":"In 2001, UNESCO declared Kasubi Tombs a World Heritage Site. Though damaged by fire in 2010, the tombs were rebuilt and continue to be a vital cultural treasure for the Baganda people and all Ugandans.","image":"coin.png","altText":"The restored Kasubi Tombs with visitors learning about Buganda heritage"}],"title":"Kasubi Tombs Story","summary":"Explore the UNESCO World Heritage Site of Kasubi Tombs","metadata":{"notes":"Migrated from legacy hardcoded Luganda story components into content_items-compatible story payloads.","status":"existing-prototype"},"questions":[{"id":"kasubi-tombs-question-1","options":["Kabaka Mwanga II","Kabaka Mutesa I","British colonizers","Daudi Chwa II"],"question":"Who built the palace that later became Kasubi Tombs?","correctAnswer":1},{"id":"kasubi-tombs-question-2","options":["1700","1802","1882","1920"],"question":"When was the palace at Kasubi Hill built?","correctAnswer":2},{"id":"kasubi-tombs-question-3","options":["He was buried with all his possessions","He was buried standing up","He was buried inside his own palace","He was buried in a foreign land"],"question":"What was unusual about Mutesa I''s burial?","correctAnswer":2},{"id":"kasubi-tombs-question-4","options":["Male warriors","Royal princesses who care for the tombs","Foreign visitors","Religious leaders"],"question":"Who are the Naalinya?","correctAnswer":1},{"id":"kasubi-tombs-question-5","options":["Two","Four","Seven","Ten"],"question":"How many Buganda kings are buried at Kasubi Tombs?","correctAnswer":1}],"languageCode":"lg"}', 62, true, '2026-07-01 09:45:23.564353+00', '2026-07-14 21:34:32.860724+00', 'published', true, 1, '2026-07-14 18:23:26+00'), ('43ba83bb-c0ac-43f5-9da1-3983ea3a5b77', 'nyn', 'word_game', 'levels', 'Runyankole Word Game', '{"levels":[{"id":"nyn-word-game-agandi","hint":"Use this when greeting someone.","image":"learning-beginner.jpg","subHint":"It can mean How are you? or Any news?","question":"A simple Runyankole greeting","targetText":"AGANDI"},{"id":"nyn-word-game-webare","hint":"Say this after someone helps you.","image":"learning-beginner.jpg","subHint":"In English, it means thank you.","question":"A polite word used to show thanks","targetText":"WEBARE"}]}', 40, true, '2026-06-19 07:58:49.994863+00', '2026-07-14 21:34:32.860724+00', 'draft', false, 1, null), ('4a8ae736-015a-4ef3-8aa4-f6b356d0f834', 'nyn', 'story', 'nyn-sample-morning-greeting', 'Agandi Omuka', '{"id":"nyn-sample-morning-greeting","pages":[{"id":"nyn-sample-morning-greeting-page-1","text":"Agandi? Nimarungi. A learner greets the family at home before starting the day.","image":"learning-beginner.jpg","altText":"A learner greeting family at home","translation":"How are you? I am fine. A learner greets the family at home before starting the day."},{"id":"nyn-sample-morning-greeting-page-2","text":"Webare, Mama. The learner thanks Mama and helps count cups of water.","image":"learning-beginner.jpg","altText":"A learner helping at home","translation":"Thank you, Mama. The learner thanks Mama and helps count cups of water."}],"title":"Agandi Omuka","summary":"Placeholder story shell using simple Runyankole greetings for language-switching tests.","metadata":{"notes":"Not final story curriculum. Keep short until reviewed by a Runyankole language specialist.","status":"placeholder"},"questions":[{"id":"nyn-sample-morning-greeting-question-1","options":["Agandi","Oli otya","Kkumi","Kabaka"],"question":"Which greeting appears in the sample story?","correctAnswer":0}],"languageCode":"nyn"}', 60, true, '2026-06-19 07:58:49.994863+00', '2026-07-14 21:34:32.860724+00', 'draft', false, 1, null), ('5608c780-5dad-4aa0-bc70-3fc26b20e384', 'nyn', 'child_menu', 'stories', 'Stories', '{"cards":[{"id":"nyn-sample-morning-greeting","image":"learning-beginner.jpg","order":1,"title":"Agandi Omuka","targetPage":"child/stories/nyn-sample-morning-greeting","description":"A short Runyankole sample greeting story"}]}', 20, true, '2026-06-19 07:58:49.994863+00', '2026-07-14 21:38:49.861195+00', 'draft', false, 2, null), ('5b7dcce2-4c65-424c-b849-d69284556670', 'lg', 'story', 'kintu', 'The Tale of Kintu', '{"id":"kintu","pages":[{"id":"kintu-page-1","text":"Long ago, Kintu was the first person on Earth. He lived alone with his cow, which was his only friend and source of food.","image":"story/kintu/kintu-cow.jpeg","altText":"Kintu standing beside his cow in a grassy field"},{"id":"kintu-page-2","text":"Gulu, the god of the sky, had many children. His daughter, Nambi, saw Kintu and fell in love with him.","image":"story/kintu/nambi.jpeg","altText":"Nambi looking at Kintu from the sky"},{"id":"kintu-page-3","text":"Nambi decided to marry Kintu and take him to live with her in the sky. But her father, Gulu, set difficult tests for Kintu to prove his worth.","image":"story/kintu/gulu-tests.jpeg","altText":"Gulu setting tests for Kintu"},{"id":"kintu-page-4","text":"First, Kintu had to eat enormous amounts of food. With help from termites who secretly ate the food, Kintu passed the test.","image":"story/kintu/kintu-food.jpeg","altText":"Kintu eating food with termites helping"},{"id":"kintu-page-5","text":"Then, Kintu had to find his special cow among thousands of identical cows. A bee helped him by landing on his cow''s horn.","image":"story/kintu/kintu-cow-search.jpeg","altText":"Kintu finding his cow with the help of a bee"},{"id":"kintu-page-6","text":"After passing all tests, Gulu allowed Kintu to marry Nambi. But he warned them to leave quickly and not come back, or Death would follow them.","image":"story/kintu/kintu-nambi.jpeg","altText":"Kintu and Nambi getting married"},{"id":"kintu-page-7","text":"Nambi remembered she forgot to bring chicken feed. Despite Kintu''s warning, she went back to get it. Death secretly followed them to Earth.","image":"story/kintu/death-follows.jpeg","altText":"Death following Kintu and Nambi to Earth"},{"id":"kintu-page-8","text":"Kintu and Nambi started a family on Earth. They became the ancestors of the Baganda people. But because Death followed them, people don''t live forever.","image":"story/kintu/kintu-family.jpeg","altText":"Kintu and Nambi with their family"}],"title":"The Tale of Kintu","summary":"Learn about Kintu, the first person on Earth according to Buganda mythology","metadata":{"notes":"Migrated from legacy hardcoded Luganda story components into content_items-compatible story payloads.","status":"existing-prototype"},"questions":[{"id":"kintu-question-1","options":["A god of the sky","The first person on Earth","Nambi''s brother","Gulu''s son"],"question":"Who was Kintu?","correctAnswer":1},{"id":"kintu-question-2","options":["Death","Nambi","Gulu","A cow"],"question":"Who fell in love with Kintu?","correctAnswer":1},{"id":"kintu-question-3","options":["To find his cow and eat enormous amounts of food","To climb the tallest mountain","To defeat Death in battle","To create the sun and moon"],"question":"What tests did Gulu set for Kintu?","correctAnswer":0},{"id":"kintu-question-4","options":["Because Gulu sent Death to watch over them","Because Death was jealous of their happiness","Because Nambi went back for chicken feed despite the warning","Because Kintu challenged Death to a race"],"question":"Why did Death follow Kintu and Nambi to Earth?","correctAnswer":2},{"id":"kintu-question-5","options":["Gulu and his children","Death and his followers","The termites who helped Kintu","Kintu and Nambi"],"question":"Who are the ancestors of the Baganda people according to this story?","correctAnswer":3}],"languageCode":"lg"}', 60, true, '2026-07-01 09:45:23.564353+00', '2026-07-14 21:34:32.860724+00', 'published', true, 1, '2026-07-14 18:23:26+00'), ('627de20b-1e72-424b-bddf-ab9b4ccf1b3c', 'lg', 'child_menu', 'stories', 'Stories', '{"cards":[{"id":"kintu","image":"kintu.jpg","order":1,"title":"Kintu","targetPage":"child/stories/kintu","description":"Learn about Kintu, the first person on Earth according to Buganda mythology"},{"id":"mwanga","image":"mwanga.jpg","order":2,"title":"Kabaka Mwanga","targetPage":"child/stories/mwanga","description":"Discover the story of Kabaka Mwanga II of Buganda"},{"id":"kasubi-tombs","image":"kasubi.jpg","order":3,"title":"Kasubi Tombs","targetPage":"child/stories/kasubi-tombs","description":"Explore the UNESCO World Heritage Site of Kasubi Tombs"},{"id":"walumbe","image":"buganda-kingdom.jpg","order":4,"title":"Walumbe and Death","targetPage":"child/stories/walumbe","description":"Learn about the story of Walumbe and the origin of death"},{"id":"ssezibwa","image":"kabaka-trail.jpg","order":5,"title":"Ssezibwa Falls","targetPage":"child/stories/ssezibwa","description":"Follow the historical origin of Ssezibwa Falls"},{"id":"millet","image":"culture.jpg","order":6,"title":"Nambi and the First Millet","targetPage":"child/stories/millet","description":"Discover the story of Nambi and the first millet"},{"id":"kasokambirye","image":"culture.jpg","order":7,"title":"Kasokambirye and the Moon","targetPage":"child/stories/kasokambirye","description":"Discover the story of Kasokambirye and the moon"},{"id":"fig-tree","image":"culture.jpg","order":8,"title":"The Generous Fig Tree","targetPage":"child/stories/fig-tree","description":"Discover the story of the generous fig tree"}]}', 20, true, '2026-06-19 07:58:49.994863+00', '2026-07-14 21:38:49.861195+00', 'published', true, 2, '2026-07-14 18:23:26+00'), ('6fed3716-3a6f-421b-9c90-01c7e739ec3f', 'lg', 'word_game', 'levels', 'Luganda Word Game', '{"levels":[{"id":"lg-word-game-level-1","hint":"You drink this every day to stay healthy","image":"rain.jpg","order":1,"subHint":"In English, it''s called ''water'' - think of the sound ''A-MA-ZI''","question":"Essential liquid that falls from the sky","targetText":"AMAZZI"},{"id":"lg-word-game-level-2","hint":"This animal barks and wags its tail when happy","image":"dog.jpg","order":2,"subHint":"In English, it''s called ''dog'' - listen for ''EM-BWA''","question":"Loyal four-legged companion in homes","targetText":"EMBWA"},{"id":"lg-word-game-level-3","hint":"Fish live in it, and it flows from one place to another","image":"river-kids.jpg","order":3,"subHint":"In English, it''s called ''river'' - say ''O-MU-GGA''","question":"Flowing water body like the mighty Nile","targetText":"OMUGGA"},{"id":"lg-word-game-level-4","hint":"This food comes from animals and is cooked on a BBQ","image":"meat.jpg","order":4,"subHint":"In English, it''s called ''meat'' - try saying ''E-NYA-MA''","question":"Protein source often grilled at Ugandan celebrations","targetText":"ENYAMA"},{"id":"lg-word-game-level-5","hint":"This animal says ''meh'' and gives milk","image":"goat.jpg","order":5,"subHint":"In English, it''s called ''goat'' - pronounce ''EM-BU-ZI''","question":"Horned animal commonly kept in rural homesteads","targetText":"EMBUZI"},{"id":"lg-word-game-level-6","hint":"These have leaves, branches, and strong trunks","image":"rainforest.jpg","order":6,"subHint":"In English, they''re called ''trees'' - say ''E-MI-TI''","question":"Tall plants that provide shade in Kampala streets","targetText":"EMITI"},{"id":"lg-word-game-level-7","hint":"This bird says ''cluck cluck'' and wakes us in the morning","image":"chicken.jpg","order":7,"subHint":"In English, it''s called ''chicken'' - pronounce ''EN-KO-KO''","question":"Feathered creature that provides breakfast eggs","targetText":"ENKOKO"},{"id":"lg-word-game-level-8","hint":"A small person who goes to school and plays games","image":"black-kid.jpg","order":8,"subHint":"In English, it''s called ''child'' - say ''O-MWA-NA''","question":"Young person treasured in Buganda culture","targetText":"OMWANA"},{"id":"lg-word-game-level-9","hint":"You wear this on your finger when you get married","image":"ring.jpeg","order":9,"subHint":"In English, it''s called ''ring'' - try saying ''EM-PE-TA''","question":"Circular ornament exchanged during traditional weddings","targetText":"EMPETA"},{"id":"lg-word-game-level-10","hint":"A place with many trees where monkeys and birds live","image":"rainforest.jpg","order":10,"subHint":"In English, it''s called ''forest'' - say ''E-KI-BI-RA''","question":"Dense collection of trees like Mabira","targetText":"EKIBIRA"},{"id":"lg-word-game-level-11","hint":"Not the city, but where farmers live and grow crops","image":"wildlife.jpg","order":11,"subHint":"In English, it''s called ''village'' - say ''E-KYA-LO''","question":"Rural settlement where many Baganda traditions originate","targetText":"EKYALO"},{"id":"lg-word-game-level-12","hint":"It has morning, afternoon, evening, and night","image":"wildlife.jpg","order":12,"subHint":"In English, it''s called ''day'' - try saying ''O-LU-NA-KU''","question":"24-hour period from sunrise to sunrise","targetText":"OLUNAKU"},{"id":"lg-word-game-level-13","hint":"Look up! It''s blue when sunny and gray when rainy","image":"wildlife.jpg","order":13,"subHint":"In English, it''s called ''sky'' - pronounce ''E-GGU-LU''","question":"Blue expanse where birds and planes fly","targetText":"EGGULU"},{"id":"lg-word-game-level-14","hint":"You eat this to grow strong and healthy","image":"wildlife.jpg","order":14,"subHint":"In English, it''s called ''food'' - say ''E-MME-RE''","question":"Nourishment served during meal times","targetText":"EMMERE"},{"id":"lg-word-game-level-15","hint":"She might be a mother, aunt, or teacher","image":"wildlife.jpg","order":15,"subHint":"In English, it''s called ''woman'' - try saying ''O-MU-KA-ZI''","question":"Female adult in Buganda society","targetText":"OMUKAZI"},{"id":"lg-word-game-level-16","hint":"It''s sharp and helps cut vegetables and meat","image":"wildlife.jpg","order":16,"subHint":"In English, it''s called ''knife'' - say ''A-KA-MBE''","question":"Cutting tool used to prepare traditional dishes","targetText":"AKAMBE"},{"id":"lg-word-game-level-17","hint":"A very small baby that cries and needs milk","image":"wildlife.jpg","order":17,"subHint":"In English, it''s called ''baby'' - pronounce ''A-KA-A-NA''","question":"Infant requiring constant care and attention","targetText":"AKAANA"},{"id":"lg-word-game-level-18","hint":"It makes the day bright and helps plants grow","image":"wildlife.jpg","order":18,"subHint":"In English, it''s called ''sun'' - say ''O-MU-SA-NA''","question":"Bright light that warms the Equator","targetText":"OMUSANA"},{"id":"lg-word-game-level-19","hint":"You hold this in your hands when drinking","image":"wildlife.jpg","order":19,"subHint":"In English, it''s called ''cup'' - pronounce ''E-KI-KO-PO''","question":"Container for drinking tea or coffee","targetText":"EKIKOPO"},{"id":"lg-word-game-level-20","hint":"Green fruit that must be cooked before eating","image":"wildlife.jpg","order":20,"subHint":"In English, they''re called ''plantains'' - say ''A-MA-TO-KE''","question":"Green fruit used to make matooke, Uganda''s staple food","targetText":"AMATOKE"},{"id":"lg-word-game-level-21","hint":"A special hat that shows someone is a king","image":"wildlife.jpg","order":21,"subHint":"In English, it''s called ''crown'' - try saying ''E-GGU-LI''","question":"Royal headwear worn by the Kabaka","targetText":"EGGULI"},{"id":"lg-word-game-level-22","hint":"They use boats and nets to catch food from the water","image":"wildlife.jpg","order":22,"subHint":"In English, they''re called ''fishermen'' - say ''A-BA-VU-BI''","question":"Men who catch tilapia on Lake Victoria","targetText":"ABAVUBI"},{"id":"lg-word-game-level-23","hint":"You read this to learn or enjoy stories","image":"wildlife.jpg","order":23,"subHint":"In English, it''s called ''book'' - pronounce ''E-KI-TA-BO''","question":"Bound pages containing knowledge or stories","targetText":"EKITABO"},{"id":"lg-word-game-level-24","hint":"Many things to read on shelves in a library","image":"wildlife.jpg","order":24,"subHint":"In English, they''re called ''books'' - say ''E-BI-TA-BO''","question":"Multiple bound publications in a library","targetText":"EBITABO"},{"id":"lg-word-game-level-25","hint":"He might be a father, uncle, or grandfather","image":"wildlife.jpg","order":25,"subHint":"In English, it''s called ''man'' - pronounce ''O-MU-SA-JJA''","question":"Adult male figure in a Ugandan household","targetText":"OMUSAJJA"},{"id":"lg-word-game-level-26","hint":"A male child who plays football and climbs trees","image":"wildlife.jpg","order":26,"subHint":"In English, it''s called ''boy'' - say ''O-MU-LE-NZI''","question":"Young male who will become an omusajja","targetText":"OMULENZI"},{"id":"lg-word-game-level-27","hint":"It keeps rain out of the house from above","image":"wildlife.jpg","order":27,"subHint":"In English, it''s called ''roof'' - pronounce ''A-KA-SO-LYA''","question":"Top covering of a traditional hut","targetText":"AKASOLYA"},{"id":"lg-word-game-level-28","hint":"The language we are learning in this game","image":"wildlife.jpg","order":28,"subHint":"This is the language name itself - say ''O-LU-GA-NDA''","question":"Native tongue of the Baganda people","targetText":"OLUGANDA"},{"id":"lg-word-game-level-29","hint":"They wear uniforms and carry schoolbags","image":"wildlife.jpg","order":29,"subHint":"In English, they''re called ''children'' - say ''A-BA-A-NA''","question":"Young ones who attend school to learn","targetText":"ABAANA"},{"id":"lg-word-game-level-30","hint":"The place where you sleep and live with family","image":"wildlife.jpg","order":30,"subHint":"In English, it''s called ''house'' - pronounce ''E-NNYU-MBA''","question":"Dwelling where families live together","targetText":"ENNYUMBA"},{"id":"lg-word-game-level-31","hint":"When cars bump into each other - be careful!","image":"wildlife.jpg","order":31,"subHint":"In English, it''s called ''accident'' - say ''A-KA-BE-NJE''","question":"Unfortunate collision or mishap on the road","targetText":"AKABENJE"},{"id":"lg-word-game-level-32","hint":"A very small creature that might make you scratch","image":"wildlife.jpg","order":32,"subHint":"In English, it''s called ''insect'' - pronounce ''A-KA-WU-KA''","question":"Tiny creature that may bite or sting","targetText":"AKAWUKA"},{"id":"lg-word-game-level-33","hint":"You go here to learn reading, writing and math","image":"wildlife.jpg","order":33,"subHint":"In English, it''s called ''school'' - say ''E-SSO-ME-RO''","question":"Institution where children receive education","targetText":"ESSOMERO"},{"id":"lg-word-game-level-34","hint":"Small white grains cooked in water until soft","image":"wildlife.jpg","order":34,"subHint":"In English, it''s called ''rice'' - pronounce ''O-MU-CEE-RE''","question":"White grain often served with groundnut sauce","targetText":"OMUCEERE"},{"id":"lg-word-game-level-35","hint":"It''s hot, bright, and helps cook food","image":"wildlife.jpg","order":35,"subHint":"In English, it''s called ''fire'' - say ''O-MU-LI-RO''","question":"Burning element used for cooking and warmth","targetText":"OMULIRO"},{"id":"lg-word-game-level-36","hint":"Moving from here to there, like on a safari","image":"wildlife.jpg","order":36,"subHint":"In English, it''s called ''journey'' - pronounce ''O-LU-GE-NDO''","question":"Expedition from one place to another","targetText":"OLUGENDO"},{"id":"lg-word-game-level-37","hint":"Coins and notes used to buy things in shops","image":"wildlife.jpg","order":37,"subHint":"In English, it''s called ''money'' - say ''E-NSI-MBI''","question":"Currency used for trade in markets","targetText":"ENSIMBI"},{"id":"lg-word-game-level-38","hint":"Being smart and knowing many important things","image":"wildlife.jpg","order":38,"subHint":"In English, it''s called ''wisdom'' - pronounce ''A-MA-GE-ZI''","question":"Intelligence and knowledge valued by elders","targetText":"AMAGEZI"},{"id":"lg-word-game-level-39","hint":"When two people like each other and play together","image":"wildlife.jpg","order":39,"subHint":"In English, it''s called ''friendship'' - say ''O-MU-KWA-NO''","question":"Bond between people who care for each other","targetText":"OMUKWANO"},{"id":"lg-word-game-level-40","hint":"Something difficult that you need to solve","image":"wildlife.jpg","order":40,"subHint":"In English, it''s called ''problem'' - pronounce ''E-KI-ZI-BU''","question":"Challenge that requires solution or patience","targetText":"EKIZIBU"},{"id":"lg-word-game-level-41","hint":"Someone who makes rhythm by hitting drums","image":"wildlife.jpg","order":41,"subHint":"In English, it''s called ''drummer'' - say ''O-MU-KU-BI''","question":"Musician who plays traditional percussion","targetText":"OMUKUBI"},{"id":"lg-word-game-level-42","hint":"A polite way to address an important woman","image":"wildlife.jpg","order":42,"subHint":"In English, it''s like saying ''lady'' or ''madam'' - pronounce ''O-MU-KYA-LA''","question":"Respected female title in formal settings","targetText":"OMUKYALA"},{"id":"lg-word-game-level-43","hint":"Like what you are trying to guess in this game","image":"wildlife.jpg","order":43,"subHint":"In English, it''s called ''word'' - say ''E-KI-GA-MBO''","question":"Unit of language that carries meaning","targetText":"EKIGAMBO"},{"id":"lg-word-game-level-44","hint":"People collect water here using jerry cans","image":"wildlife.jpg","order":44,"subHint":"In English, it''s called ''well'' - pronounce ''O-LU-ZZI''","question":"Source of fresh water in villages","targetText":"OLUZZI"},{"id":"lg-word-game-level-45","hint":"Youwalk on this to get from one place to another","image":"wildlife.jpg","order":45,"subHint":"In English, it''s called ''road'' or ''path'' - pronounce ''E-KKU-BO''","question":"Path taken between destinations","targetText":"EKKUBO"},{"id":"lg-word-game-level-46","hint":"Something fun you do with friends for enjoyment","image":"wildlife.jpg","order":46,"subHint":"In English, it''s called ''game'' or ''play'' - say ''O-MU-ZA-NNYO''","question":"Activity played for enjoyment or competition","targetText":"OMUZANNYO"},{"id":"lg-word-game-level-47","hint":"Bigger than a pond, with lots of fish and water","image":"wildlife.jpg","order":47,"subHint":"In English, it''s called ''lake'' - pronounce ''E-NNYA-NJA''","question":"Large body of water like Victoria or Kyoga","targetText":"ENNYANJA"},{"id":"lg-word-game-level-48","hint":"The king''s son who might become king someday","image":"wildlife.jpg","order":48,"subHint":"In English, it''s called ''prince'' - say ''O-MU-LA-NGI-RA''","question":"Son of the Kabaka, heir to Buganda kingdom","targetText":"OMULANGIRA"},{"id":"lg-word-game-level-49","hint":"A place with runways where people travel by air","image":"wildlife.jpg","order":49,"subHint":"In English, it''s called ''airport'' or ''field'' - pronounce ''E-KI-SAA-WE''","question":"Terminal where planes land and take off","targetText":"EKISAAWE"},{"id":"lg-word-game-level-50","hint":"Someone who makes beautiful sounds with their mouth","image":"wildlife.jpg","order":50,"subHint":"In English, it''s called ''singer'' - say ''O-MU-YI-MBI''","question":"Performer who uses voice to create music","targetText":"OMUYIMBI"}]}', 40, true, '2026-06-19 07:58:49.994863+00', '2026-07-14 21:34:32.860724+00', 'published', true, 1, '2026-07-14 18:23:26+00'), ('793a4473-c0b5-4398-ae87-ad6ee1ad25f3', 'nyn', 'counting_game', 'stages', 'Runyankole Counting Samples', '{"title":"Runyankole Counting Samples","stages":[{"id":1,"title":"Basic Counting Samples (1-5)","levels":5,"prompt":"Bara {item}. How many {item} do you see?","useBunches":false,"description":"Placeholder Runyankole counting labels for language-switching tests.","numbersRange":{"max":5,"min":1},"usesCurrency":false}],"numbers":[{"audio":"correct.mp3","number":1,"targetText":"Emwe"},{"audio":"correct.mp3","number":2,"targetText":"Ibiri"},{"audio":"correct.mp3","number":3,"targetText":"Ishatu"},{"audio":"correct.mp3","number":4,"targetText":"Ina"},{"audio":"correct.mp3","number":5,"targetText":"Itaano"}],"currency":[],"culturalItems":[{"name":"cups","image":"coin.png"},{"name":"beans","image":"bean.png"},{"name":"baskets","image":"basket.png"}]}', 50, true, '2026-06-19 07:58:49.994863+00', '2026-07-14 21:34:32.860724+00', 'draft', false, 1, null), ('8295d3df-60a2-4bba-b4d2-83e1ea2a4f75', 'lg', 'story', 'walumbe', 'The Tale of Walumbe', '{"id":"walumbe","pages":[{"id":"walumbe-page-1","text":"After Kintu and Nambi came to Earth, they were followed by Walumbe, who was Death, Nambi''s brother. At first, Walumbe lived peacefully among the people.","image":"coin.png","altText":"Walumbe arriving on Earth after Kintu and Nambi"},{"id":"walumbe-page-2","text":"One day, Walumbe asked Kintu to give him one of his daughters as a wife. Kintu refused, knowing that no good could come from such a union with Death.","image":"coin.png","altText":"Walumbe speaking with Kintu who refuses his request"},{"id":"walumbe-page-3","text":"Angered by the rejection, Walumbe began to take Kintu''s children, one by one. He would hide them underground in the caverns where he lived, causing great sorrow.","image":"coin.png","altText":"Walumbe taking children into underground caverns"},{"id":"walumbe-page-4","text":"Kintu appealed to Gulu, the sky god. Gulu sent his son, Kayikuuzi, to capture Walumbe and take him back to the sky so he would stop bringing death to Earth.","image":"coin.png","altText":"Kintu appealing to Gulu in the sky"},{"id":"walumbe-page-5","text":"Kayikuuzi chased Walumbe across the land. Finally, Walumbe fled into the ground at a place now called Ttanda, and Kayikuuzi followed him into the deep caves.","image":"coin.png","altText":"Kayikuuzi chasing Walumbe who is diving into the ground"},{"id":"walumbe-page-6","text":"The chase went on for days. Each time Kayikuuzi almost caught Walumbe, the people above ground would make noise, warning Walumbe, who would escape deeper into the earth.","image":"coin.png","altText":"People making noise above ground as the chase continues below"},{"id":"walumbe-page-7","text":"Eventually, Kayikuuzi gave up. He told the people, ''Because you warned Walumbe, I cannot capture him. Now death will remain on Earth forever.''","image":"coin.png","altText":"Kayikuuzi emerging from the ground speaking to the people"},{"id":"walumbe-page-8","text":"To this day, the Baganda say that Walumbe still lives in the caves of Ttanda, and that is why death comes to all people. The caves remain a sacred and feared place.","image":"coin.png","altText":"The caves of Ttanda with people paying respects from a distance"}],"title":"The Tale of Walumbe","summary":"Learn about the story of Walumbe and the origin of death","metadata":{"notes":"Migrated from legacy hardcoded Luganda story components into content_items-compatible story payloads.","status":"existing-prototype"},"questions":[{"id":"walumbe-question-1","options":["Her father","Her husband","Her brother","Her son"],"question":"Who was Walumbe in relation to Nambi?","correctAnswer":2},{"id":"walumbe-question-2","options":["A piece of land","One of his daughters as a wife","Help building a home","Food and shelter"],"question":"What did Walumbe ask from Kintu?","correctAnswer":1},{"id":"walumbe-question-3","options":["Left peacefully","Began taking Kintu''s children one by one","Asked Gulu for help","Built his own kingdom"],"question":"What did Walumbe do when Kintu refused his request?","correctAnswer":1},{"id":"walumbe-question-4","options":["Nambi","Kintu","Kayikuuzi","A powerful animal"],"question":"Who did Gulu send to capture Walumbe?","correctAnswer":2},{"id":"walumbe-question-5","options":["Walumbe was too strong","The people warned Walumbe by making noise","Gulu changed his mind","Kintu protected Walumbe"],"question":"Why couldn''t Kayikuuzi capture Walumbe?","correctAnswer":1}],"languageCode":"lg"}', 63, true, '2026-07-01 09:45:23.564353+00', '2026-07-14 21:34:32.860724+00', 'published', true, 1, '2026-07-14 18:23:26+00'), ('885e18f9-192e-4ca1-a0e8-5ec6bd5b630f', 'lg', 'story', 'ssezibwa', 'Ssezibwa Falls', '{"id":"ssezibwa","pages":[{"id":"ssezibwa-page-1","text":"Long ago in Buganda, a woman named Nakkungu Tebatuusa was expecting twins. As she traveled to visit her parents, something extraordinary happened.","image":"coin.png","altText":"A pregnant woman traveling through the countryside"},{"id":"ssezibwa-page-2","text":"Instead of giving birth to children, Nakkungu gave birth to two rivers. The first river was Ssezibwa, a boy river. The second was Bwanda, a girl river.","image":"coin.png","altText":"Rivers flowing from a mountainside"},{"id":"ssezibwa-page-3","text":"The Ssezibwa River flowed strongly eastward, cutting through rocks and creating beautiful waterfalls. The river spoke to his mother, telling her not to worry.","image":"coin.png","altText":"Powerful waterfall flowing through rocks"},{"id":"ssezibwa-page-4","text":"\\"I will be more useful as a river than as a human,\\" Ssezibwa said. \\"I will provide water for animals, plants, and people. I will be remembered forever.\\"","image":"coin.png","altText":"Animals drinking from the river"},{"id":"ssezibwa-page-5","text":"The Buganda people believed that Ssezibwa Falls was a special place where spirits lived. People would visit the falls to make offerings and ask for blessings.","image":"coin.png","altText":"People making offerings at the waterfall"},{"id":"ssezibwa-page-6","text":"If someone needed good fortune, they would throw cowrie shells or coins into the water. Farmers would ask for rain, and fishermen would ask for a good catch.","image":"coin.png","altText":"People throwing offerings into the river"},{"id":"ssezibwa-page-7","text":"Even powerful kings of Buganda would visit Ssezibwa Falls before important battles or decisions. They believed the river spirit would give them wisdom and strength.","image":"coin.png","altText":"A king visiting the falls with attendants"},{"id":"ssezibwa-page-8","text":"To this day, Ssezibwa Falls remains a sacred place in Uganda. The river that began as a child continues to nurture life and inspire wonder in all who visit.","image":"coin.png","altText":"Modern visitors admiring the beautiful falls"}],"title":"Ssezibwa Falls","summary":"Follow the historical origin of Ssezibwa Falls","metadata":{"notes":"Migrated from legacy hardcoded Luganda story components into content_items-compatible story payloads.","status":"existing-prototype"},"questions":[{"id":"ssezibwa-question-1","options":["She gave birth to twins","She gave birth to rivers","She gave birth in a waterfall","She gave birth to spirits"],"question":"What was unusual about Nakkungu Tebatuusa''s birth experience?","correctAnswer":1},{"id":"ssezibwa-question-2","options":["Nile and Victoria","Kagera and Katonga","Ssezibwa and Bwanda","Mabira and Mpanga"],"question":"What were the names of the two rivers born to Nakkungu?","correctAnswer":2},{"id":"ssezibwa-question-3","options":["To avoid human responsibilities","To provide water for animals, plants, and people","To create beautiful waterfalls","To connect to other rivers"],"question":"Why did Ssezibwa say he would be more useful as a river?","correctAnswer":1},{"id":"ssezibwa-question-4","options":["Flowers and fruits","Cowrie shells or coins","Wooden carvings","Clay pots"],"question":"What did people throw into Ssezibwa Falls to ask for good fortune?","correctAnswer":1},{"id":"ssezibwa-question-5","options":["Fishermen","Farmers","Kings of Buganda","Foreign visitors"],"question":"Who would visit Ssezibwa Falls before important battles or decisions?","correctAnswer":2}],"languageCode":"lg"}', 64, true, '2026-07-01 09:45:23.564353+00', '2026-07-14 21:34:32.860724+00', 'published', true, 1, '2026-07-14 18:23:26+00'), ('9471673d-ca6b-4b2c-8f8b-336241740629', 'lg', 'story', 'kasokambirye', 'Kasokambirye and the Moon', '{"id":"kasokambirye","pages":[{"id":"kasokambirye-page-1","text":"In the kingdom of Buganda, there was a brave hunter named Kasokambirye. He was known for his incredible aim with a spear and his fearless heart.","image":"coin.png","altText":"A hunter with a spear standing proudly"},{"id":"kasokambirye-page-2","text":"One night, Kasokambirye looked up at the bright full moon. ''Why does the moon glow so brightly while we must live in darkness?'' he wondered aloud.","image":"coin.png","altText":"Kasokambirye looking up at the full moon"},{"id":"kasokambirye-page-3","text":"His friends laughed at him. ''No one can reach the moon! It is too far away,'' they said. But Kasokambirye was determined to prove them wrong.","image":"coin.png","altText":"Friends laughing as Kasokambirye points at the moon"},{"id":"kasokambirye-page-4","text":"Kasokambirye began to build a tower of trees, climbing higher and higher towards the sky. He worked for many days and nights, never stopping to rest.","image":"coin.png","altText":"Kasokambirye building a tall tower of trees"},{"id":"kasokambirye-page-5","text":"Finally, his tower reached so high that he could almost touch the moon. ''Just one more tree!'' he called down to his friends. ''Then I will bring the moon to Earth!''","image":"coin.png","altText":"Kasokambirye at the top of his tower reaching for the moon"},{"id":"kasokambirye-page-6","text":"But as he placed the last tree on his tower, the structure began to sway. The wind blew strongly, and the tower tumbled down, taking Kasokambirye with it.","image":"coin.png","altText":"The tower collapsing as Kasokambirye falls"},{"id":"kasokambirye-page-7","text":"As he fell, Kasokambirye grabbed onto the moon. Instead of bringing the moon down, the moon pulled him up. To everyone''s amazement, he disappeared into the sky.","image":"coin.png","altText":"Kasokambirye being pulled up to the moon"},{"id":"kasokambirye-page-8","text":"The Baganda people say that on clear nights, you can see Kasokambirye''s silhouette on the moon. His courage and ambition remind us to always reach for the stars.","image":"coin.png","altText":"A silhouette visible on the full moon"}],"title":"Kasokambirye and the Moon","summary":"Discover the story of Kasokambirye and the moon","metadata":{"notes":"Migrated from legacy hardcoded Luganda story components into content_items-compatible story payloads.","status":"existing-prototype"},"questions":[{"id":"kasokambirye-question-1","options":["His wisdom and patience","His incredible aim with a spear and fearless heart","His ability to talk to animals","His skill at building houses"],"question":"What was Kasokambirye known for?","correctAnswer":1},{"id":"kasokambirye-question-2","options":["To prove his friends wrong","To bring light to Earth during night","To meet moon spirits","To become famous"],"question":"Why did Kasokambirye want to reach the moon?","correctAnswer":1},{"id":"kasokambirye-question-3","options":["By climbing a mountain","By building a tower of trees","By taming a giant bird","By using magic"],"question":"How did Kasokambirye try to reach the moon?","correctAnswer":1},{"id":"kasokambirye-question-4","options":["He fell back to Earth","He grabbed onto the moon and was pulled up","He was rescued by his friends","He built another tower"],"question":"What happened when Kasokambirye''s tower collapsed?","correctAnswer":1},{"id":"kasokambirye-question-5","options":["Kasokambirye''s tower reaching to the sky","Kasokambirye''s silhouette on the moon","The path Kasokambirye took to the moon","Kasokambirye''s spear floating in the sky"],"question":"According to the story, what can be seen on clear nights?","correctAnswer":1}],"languageCode":"lg"}', 66, true, '2026-07-01 09:45:23.564353+00', '2026-07-14 21:34:32.860724+00', 'published', true, 1, '2026-07-14 18:23:26+00'), ('97b74223-b348-42d9-8013-62467952f56e', 'lg', 'counting_gam