4","audio":"correct.mp3","image":"learning-beginner.jpg","order":4,"english":"Small","example":"Akatunda katono.","targetText":"Kitono","exampleTranslation":"The fruit is small."}],"isLocked":true}],"isLocked":true,"description":"Actions and descriptions","requiredScore":90},{"id":4,"color":"#FF7675","image":"coin.png","order":4,"title":"Advanced","levels":[{"id":7,"order":1,"title":"Nature","words":[{"id":"lg-learning-stage-4-level-7-word-1","audio":"correct.mp3","image":"learning-beginner.jpg","order":1,"english":"Sky","example":"Eggulu lino bbululu.","targetText":"Eggulu","exampleTranslation":"The sky is blue."},{"id":"lg-learning-stage-4-level-7-word-2","audio":"correct.mp3","image":"learning-beginner.jpg","order":2,"english":"Star","example":"Emmunyeenye nyingi ziri mu ggulu.","targetText":"Emmunyeenye","exampleTranslation":"There are many stars in the sky."},{"id":"lg-learning-stage-4-level-7-word-3","audio":"correct.mp3","image":"learning-beginner.jpg","order":3,"english":"Sun","example":"Omusana gwaka nnyo leero.","targetText":"Omusana","exampleTranslation":"The sun is very hot today."},{"id":"lg-learning-stage-4-level-7-word-4","audio":"correct.mp3","image":"learning-beginner.jpg","order":4,"english":"Moon","example":"Omwezi gwaka ekiro.","targetText":"Omwezi","exampleTranslation":"The moon shines at night."}],"isLocked":true},{"id":8,"order":2,"title":"Environment","words":[{"id":"lg-learning-stage-4-level-8-word-1","audio":"correct.mp3","image":"learning-beginner.jpg","order":1,"english":"Land","example":"Olukalu luno lugimu.","targetText":"Olukalu","exampleTranslation":"This land is fertile."},{"id":"lg-learning-stage-4-level-8-word-2","audio":"correct.mp3","image":"learning-beginner.jpg","order":2,"english":"Forest","example":"Ekibira kino kinene.","targetText":"Ekibira","exampleTranslation":"This forest is big."},{"id":"lg-learning-stage-4-level-8-word-3","audio":"correct.mp3","image":"learning-beginner.jpg","order":3,"english":"Lake","example":"Enyanja Victoria nnene.","targetText":"Enyanja","exampleTranslation":"Lake Victoria is big."},{"id":"lg-learning-stage-4-level-8-word-4","audio":"correct.mp3","image":"learning-beginner.jpg","order":4,"english":"Mountain","example":"Olusozi luno luwanvu.","targetText":"Olusozi","exampleTranslation":"This mountain is tall."}],"isLocked":true}],"isLocked":true,"description":"Nature and environment","requiredScore":130},{"id":5,"color":"#A29BFE","image":"coin.png","order":5,"title":"Expert","levels":[{"id":9,"order":1,"title":"Time Expressions","words":[{"id":"lg-learning-stage-5-level-9-word-1","audio":"correct.mp3","image":"learning-beginner.jpg","order":1,"english":"Today","example":"Leero nnagenda mu kibuga.","targetText":"Leero","exampleTranslation":"Today I went to the city."},{"id":"lg-learning-stage-5-level-9-word-2","audio":"correct.mp3","image":"learning-beginner.jpg","order":2,"english":"Tomorrow","example":"Enkya tugenda mu ssomero.","targetText":"Enkya","exampleTranslation":"Tomorrow we go to school."},{"id":"lg-learning-stage-5-level-9-word-3","audio":"correct.mp3","image":"learning-beginner.jpg","order":3,"english":"Yesterday","example":"Jjo twalabye film.","targetText":"Jjo","exampleTranslation":"Yesterday we watched a film."},{"id":"lg-learning-stage-5-level-9-word-4","audio":"correct.mp3","image":"learning-beginner.jpg","order":4,"english":"Hour/Time","example":"Essawa mmeka?","targetText":"Essawa","exampleTranslation":"What time is it?"}],"isLocked":true},{"id":10,"order":2,"title":"Expressions","words":[{"id":"lg-learning-stage-5-level-10-word-1","audio":"correct.mp3","image":"learning-beginner.jpg","order":1,"english":"Nice to meet you","example":"Nsanyuse okukulaba nate.","targetText":"Nsanyuse okukulaba","exampleTranslation":"Nice to meet you again."},{"id":"lg-learning-stage-5-level-10-word-2","audio":"correct.mp3","image":"learning-beginner.jpg","order":2,"english":"No problem","example":"Tewali mutawaana, nsobola okukuyamba.","targetText":"Tewali mutawaana","exampleTranslation":"No problem, I can help you."},{"id":"lg-learning-stage-5-level-10-word-3","audio":"correct.mp3","image":"learning-beginner.jpg","order":3,"english":"I love you","example":"Nkwagala nnyo.","targetText":"Nkwagala","exampleTranslation":"I love you very much."},{"id":"lg-learning-stage-5-level-10-word-4","audio":"correct.mp3","image":"learning-beginner.jpg","order":4,"english":"I don''t know","example":"Simanyi luganda lungi.","targetText":"Simanyi","exampleTranslation":"I don''t know good Luganda."}],"isLocked":true}],"isLocked":true,"description":"Complex concepts and expressions","requiredScore":170}]}', 30, true, '2026-06-19 07:58:49.994863+00', '2026-07-14 21:34:32.860724+00', 'published', true, 1, '2026-07-14 18:23:26+00'), ('d6511daa-08e3-421b-879e-d86c21502e52', 'nyn', 'child_menu', 'games', 'Games', '{"cards":[{"id":"words","image":"african-focus.png","title":"Words","targetPage":"child/games/wordgame","description":"Practice Runyankole sample words"},{"id":"learning","image":"african-patterns.png","title":"Learning","targetPage":"child/games/learninggame","description":"Learn starter Runyankole words and examples"},{"id":"numbers","image":"numbers.png","title":"Numbers","targetPage":"child/games/lugandacountinggame","description":"Count with Runyankole sample number labels"}]}', 10, true, '2026-06-19 07:58:49.994863+00', '2026-07-14 21:34:32.860724+00', 'draft', false, 1, null), ('d6ae546c-8c88-4049-bb05-2fbdc34b245e', 'lg', 'child_menu', 'coloring', 'Coloring', '{"cards":[{"id":"emblem","image":"emblem.png","order":1,"title":"Buganda Emblem","targetPage":"child/games/coloring/emblem","description":"Buganda''s emblem"},{"id":"king","image":"king.jpg","order":2,"title":"Kings","targetPage":"child/games/coloring/king","description":"King''s image"},{"id":"animals","image":"cow.png","order":3,"title":"Animals","targetPage":"child/games/coloring/animals","description":"Color African wildlife animals"},{"id":"shapes","image":"shapes.jpg","order":4,"title":"Shapes","targetPage":"child/games/coloring/shapes","description":"Color different shapes"},{"id":"masks","image":"mask.png","order":5,"title":"Masks","targetPage":"child/games/coloring/mask","description":"Color traditional African masks"}]}', 15, true, '2026-07-14 21:34:23.334371+00', '2026-07-14 21:34:32.860724+00', 'published', true, 1, '2026-07-14 18:23:26+00'), ('dd1692da-91aa-403d-879c-62d0cb2b814f', 'lg', 'puzzle_game', 'puzzles', 'Buganda Heritage Puzzles', '{"title":"Buganda Heritage Puzzles","puzzles":[{"id":1,"name":"Kasubi Tombs","image":"puzzles/kasubi-tombs.jpg","order":1,"description":"A UNESCO World Heritage site and burial ground of Buganda kings"},{"id":2,"name":"Buganda Royal Drums","image":"puzzles/buganda-drums.jpg","order":2,"description":"Traditional royal drums used in Buganda ceremonies"},{"id":3,"name":"Lubiri Palace","image":"puzzles/lubiri-palace.jpg","order":3,"description":"The palace of the Kabaka (King) of Buganda"}]}', 56, true, '2026-07-14 21:34:23.334371+00', '2026-07-14 21:34:32.860724+00', 'published', true, 1, '2026-07-14 18:23:26+00'), ('e91d5774-4b8c-466d-be6b-9f785a6c1c44', 'lg', 'story', 'millet', 'Nnambi and the Millet', '{"id":"millet","pages":[{"id":"millet-page-1","text":"Long ago when the Baganda people first settled in their lands, they did not know how to grow food. They survived by hunting animals and gathering wild fruits.","image":"coin.png","altText":"People hunting and gathering wild fruits"},{"id":"millet-page-2","text":"A woman named Nnambi lived with her husband in a small hut. Each day grew harder as there were more people but less food to be found in the forests.","image":"coin.png","altText":"Nnambi and her husband looking worried about food"},{"id":"millet-page-3","text":"One night, Nnambi had a dream. A beautiful spirit came to her and said, ''Follow the morning star until you reach the red hill. There you will find what your people need.''","image":"coin.png","altText":"Nnambi dreaming of a spirit speaking to her"},{"id":"millet-page-4","text":"When she awoke, Nnambi told no one about her dream. Before sunrise, she followed the morning star, walking for many hours until she reached a hill with reddish soil.","image":"coin.png","altText":"Nnambi walking alone following the morning star"},{"id":"millet-page-5","text":"On the hill grew tall plants with golden seeds that Nnambi had never seen before. The spirit appeared again and said, ''This is millet. Take these seeds and learn to grow them.''","image":"coin.png","altText":"Nnambi discovering millet plants on the red hill"},{"id":"millet-page-6","text":"The spirit showed Nnambi how to plant the seeds, tend the young plants, and harvest the grain when it was ripe. She also learned how to grind the millet and cook it.","image":"coin.png","altText":"The spirit teaching Nnambi how to plant and prepare millet"},{"id":"millet-page-7","text":"Nnambi returned to her village carrying the precious millet seeds. She taught everyone what she had learned, and soon fields of golden millet were growing throughout the land.","image":"coin.png","altText":"Nnambi sharing millet seeds with villagers"},{"id":"millet-page-8","text":"The Baganda people no longer went hungry. They honored Nnambi as a hero, and to this day, millet porridge is a sacred food in Buganda, used in many important ceremonies and celebrations.","image":"coin.png","altText":"People celebrating with millet porridge at a ceremony"}],"title":"Nnambi and the Millet","summary":"Discover the story of Nambi and the first millet","metadata":{"notes":"Migrated from legacy hardcoded Luganda story components into content_items-compatible story payloads.","status":"existing-prototype"},"questions":[{"id":"millet-question-1","options":["By trading with neighbors","By hunting animals and gathering wild fruits","By fishing in lakes","By stealing from other tribes"],"question":"How did the Baganda people survive before they knew how to grow food?","correctAnswer":1},{"id":"millet-question-2","options":["Build a new village","Follow the morning star to the red hill","Pray to the ancestors","Search for a hidden treasure"],"question":"What did the spirit in Nnambi''s dream tell her to do?","correctAnswer":1},{"id":"millet-question-3","options":["Gold and jewels","A magic spring","Tall plants with golden seeds (millet)","A new type of animal"],"question":"What did Nnambi discover on the red hill?","correctAnswer":2},{"id":"millet-question-4","options":["How to hunt better","How to plant, tend, harvest, and cook millet","How to predict the weather","How to make clothing"],"question":"What did the spirit teach Nnambi?","correctAnswer":1},{"id":"millet-question-5","options":["Because it has healing properties","Because it is used in many important ceremonies","Because only royalty can eat it","Because it glows in the dark"],"question":"Why is millet porridge considered sacred in Buganda?","correctAnswer":1}],"languageCode":"lg"}', 65, true, '2026-07-01 09:45:23.564353+00', '2026-07-14 21:34:32.860724+00', 'published', true, 1, '2026-07-14 18:23:26+00');